/**
 * Local mesh fixture tests.
 *
 * Validates `createLocalMeshPipeline` shapes a Pipeline + two Stations
 * matching the spawn-local-mesh.sh contract (ports 8081/8082, entry/exit
 * roles, layer split at floor(totalLayers/2)), and that `pingLocalMesh`
 * stays exception-free when no server is listening.
 */

import { describe, expect, it } from 'vitest';

import {
  createLocalMeshPipeline,
  pingLocalMesh,
} from '../test-fixtures/local-mesh';
import { Pipeline } from '../pipeline';

describe('createLocalMeshPipeline', () => {
  it('createLocalMeshPipeline_with_defaults', () => {
    const bundle = createLocalMeshPipeline();

    expect(bundle.pipeline).toBeInstanceOf(Pipeline);
    expect(bundle.stationAUrl).toBe('http://localhost:8081');
    expect(bundle.stationBUrl).toBe('http://localhost:8082');
    expect(bundle.model).toBe('qwen-coder-7b');
    expect(bundle.totalLayers).toBe(28);
    expect(bundle.midLayer).toBe(14);

    // Station A: entry, layers [0, 14)
    expect(bundle.stationA.startLayer).toBe(0);
    expect(bundle.stationA.endLayer).toBe(14);
    expect(bundle.stationA.role).toBe('entry');

    // Station B: exit, layers [14, 28)
    expect(bundle.stationB.startLayer).toBe(14);
    expect(bundle.stationB.endLayer).toBe(28);
    expect(bundle.stationB.role).toBe('exit');

    // Pipeline wired with exactly the two stations.
    expect(bundle.pipeline.entryStation).toBe(bundle.stationA);
    expect(bundle.pipeline.exitStation).toBe(bundle.stationB);
  });

  it('createLocalMeshPipeline_with_custom_urls', () => {
    const bundle = createLocalMeshPipeline({
      stationAUrl: 'http://127.0.0.1:9001',
      stationBUrl: 'http://127.0.0.1:9002',
      totalLayers: 32,
      hiddenDim: 2048,
      model: 'test-model',
    });

    expect(bundle.stationAUrl).toBe('http://127.0.0.1:9001');
    expect(bundle.stationBUrl).toBe('http://127.0.0.1:9002');
    expect(bundle.model).toBe('test-model');
    expect(bundle.totalLayers).toBe(32);
    expect(bundle.midLayer).toBe(16);

    expect(bundle.stationA.startLayer).toBe(0);
    expect(bundle.stationA.endLayer).toBe(16);
    expect(bundle.stationB.startLayer).toBe(16);
    expect(bundle.stationB.endLayer).toBe(32);
  });

  it('createLocalMeshPipeline_rejects_too_few_layers', () => {
    expect(() => createLocalMeshPipeline({ totalLayers: 1 })).toThrow();
    expect(() => createLocalMeshPipeline({ totalLayers: 0 })).toThrow();
  });
});

describe('pingLocalMesh', () => {
  it('pingLocalMesh_returns_false_when_no_server', async () => {
    // Use clearly-unused high ports; even if something IS bound there,
    // /health is unlikely to respond OK.
    const ok = await pingLocalMesh({
      stationAUrl: 'http://127.0.0.1:1',
      stationBUrl: 'http://127.0.0.1:2',
    });
    expect(ok).toBe(false);
  });
});
